mapper.select:
select rel.id,
       rel.source_item_id,
       rel.target_item_id,
       case when rel.source_item_id = #{archiveItemId}
            then rel.target_item_id else rel.source_item_id end as related_item_id,
       case when rel.source_item_id = #{archiveItemId}
            then 'OUTGOING' else 'INCOMING' end as direction,
       rel.created_at,
       ti.fonds_code as related_fonds_code,
       ti.fonds_name as related_fonds_name,
       ti.category_code as related_category_code,
       ti.category_name as related_category_name,
       ti.archive_no as related_archive_no
from am_archive_item_relation rel
join am_archive_item ti
  on ti.id = case when rel.source_item_id = #{archiveItemId}
                  then rel.target_item_id else rel.source_item_id end
  and ti.deleted_flag = false
where (rel.source_item_id = #{archiveItemId}
       or rel.target_item_id = #{archiveItemId})

    and (

        (
        ti.category_code = #{scope.categoryCode}
        and (

            (

                ti.fonds_code in

                    #{fondsCode}



                and
                ti.security_level_id in

                    #{securityLevelId}



                and
                ti.retention_period_id in

                    #{retentionPeriodId}



                and
                exists (
                    select 1
                    from ${scope.tableName} d
                    where d.id = ti.id
                      and d.deleted_flag = false



                                and d.${condition.columnName} = #{condition.value}


                                and d.${condition.columnName} in

                                    #{conditionValue}



                                and d.${condition.columnName} is null


                                and d.${condition.columnName} is not null



                )


                true

            )

        )
        )


        false

    )




            and rel.id < #{page.cursorId}


            and rel.id > #{page.cursorId}



order by rel.id

    desc
    asc

limit #{page.rowLimit}

mapper.delete:
