mapper.select:
select id,
       item_id,
       line_order

       , ${columnName}

from ${query.tableName}
where item_id = #{query.itemId}
  and deleted_flag = false



            and (line_order < #{query.cursorLineOrder}
                 or (line_order = #{query.cursorLineOrder} and id < #{query.cursorId}))


            and (line_order > #{query.cursorLineOrder}
                 or (line_order = #{query.cursorLineOrder} and id > #{query.cursorId}))



order by line_order

    desc
    asc
,
id

    desc
    asc

limit #{query.rowLimit}

